    async def test_multi_cycle_stop_notification_subagent_stop(self, db) -> None:
        """Reproduces real session 73b9a18e: multiple work→Stop→Notification
        cycles with SubagentStop events arriving after the last Notification.
        derived_state must be 'ready' (from the last Stop), not null."""
        # First work cycle
        await _seed_hook(
            db,
            session_id="sa",
            pid=10,
            event_name="UserPromptSubmit",
            tool_name=None,
            received_at=100.0,
        )
        await _seed_hook(
            db,
            session_id="sa",
            pid=10,
            event_name="PreToolUse",
            tool_name="Bash",
            received_at=110.0,
        )
        await _seed_hook(
            db,
            session_id="sa",
            pid=10,
            event_name="PostToolUse",
            tool_name="Bash",
            received_at=120.0,
        )
        await _seed_hook(
            db,
            session_id="sa",
            pid=10,
            event_name="Stop",
            tool_name=None,
            received_at=130.0,
        )
        await _seed_hook(
            db,
            session_id="sa",
            pid=10,
            event_name="Notification",
            tool_name=None,
            received_at=140.0,
        )
        # First subagent finishes (was spawned during the work cycle)
        await _seed_hook(
            db,
            session_id="sa",
            pid=10,
            event_name="SubagentStop",
            agent_id="agent-1",
            received_at=150.0,
        )
        # Second work cycle
        await _seed_hook(
            db,
            session_id="sa",
            pid=10,
            event_name="UserPromptSubmit",
            tool_name=None,
            received_at=160.0,
        )
        await _seed_hook(
            db,
            session_id="sa",
            pid=10,
            event_name="PreToolUse",
            tool_name="Edit",
            received_at=170.0,
        )
        await _seed_hook(
            db,
            session_id="sa",
            pid=10,
            event_name="PostToolUse",
            tool_name="Edit",
            received_at=180.0,
        )
        await _seed_hook(
            db,
            session_id="sa",
            pid=10,
            event_name="Stop",
            tool_name=None,
            received_at=190.0,
        )
        await _seed_hook(
            db,
            session_id="sa",
            pid=10,
            event_name="Notification",
            tool_name=None,
            received_at=200.0,
        )
        # Second subagent finishes last — absolute latest event
        await _seed_hook(
            db,
            session_id="sa",
            pid=10,
            event_name="SubagentStop",
            agent_id="agent-2",
            received_at=210.0,
        )

        detail = await queries.get_session_by_id(db, session_id="sa")
        assert detail["last_event"] == "SubagentStop"
        assert detail["derived_state"] == "ready"

        sessions = await queries.get_sessions(db)
        assert sessions[0]["derived_state"] == "ready"

        procs = await queries.get_processes(db)
        assert procs[0]["derived_state"] == "ready"

